const candidate = $('Read Candidates Sheet').item.json;
const llmResponse = $input.item.json;

// Extract and parse the LLM's JSON content
let scoring;
try {
  const rawContent = llmResponse.choices[0].message.content;
  scoring = JSON.parse(rawContent);
} catch (e) {
  // Malformed LLM response — return error row
  return [{
    json: {
      name: candidate.name,
      email: candidate.email,
      location: candidate.location,
      years_experience: candidate.years_experience,
      current_role: candidate.current_role,
      ats_experience: candidate.ats_experience,
      ashby_score: 'ERROR',
      coordination_score: 'ERROR',
      english_score: 'ERROR',
      startup_score: 'ERROR',
      automation_score: 'ERROR',
      overall_score: 'ERROR',
      tier: 'ERROR',
      top_strengths: 'LLM parsing failed',
      main_gap: 'LLM parsing failed',
      recommendation: `Scoring failed: ${e.message}. Raw: ${llmResponse.choices?.[0]?.message?.content?.substring(0, 100) ?? 'no content'}`,
      scored_at: new Date().toISOString(),
    }
  }];
}

// Validate required fields exist
const required = ['ashby_score','coordination_score','english_score','startup_score','automation_score','overall_score','tier'];
const missing = required.filter(k => scoring[k] === undefined || scoring[k] === null);

if (missing.length > 0) {
  return [{
    json: {
      name: candidate.name,
      email: candidate.email,
      location: candidate.location,
      years_experience: candidate.years_experience,
      current_role: candidate.current_role,
      ats_experience: candidate.ats_experience,
      ashby_score: 'ERROR',
      coordination_score: 'ERROR',
      english_score: 'ERROR',
      startup_score: 'ERROR',
      automation_score: 'ERROR',
      overall_score: 'ERROR',
      tier: 'ERROR',
      top_strengths: `Missing fields: ${missing.join(', ')}`,
      main_gap: 'Incomplete LLM response',
      recommendation: 'Manual review required — LLM returned incomplete scoring.',
      scored_at: new Date().toISOString(),
    }
  }];
}

// Recompute weighted score server-side to prevent LLM arithmetic errors
const recomputed = (
  Number(scoring.ashby_score)        * 0.30 +
  Number(scoring.coordination_score) * 0.25 +
  Number(scoring.english_score)      * 0.20 +
  Number(scoring.startup_score)      * 0.15 +
  Number(scoring.automation_score)   * 0.10
);

const recomputedRounded = Math.round(recomputed * 10) / 10;

const tierMap = [
  [7.5, 'Strong Yes'],
  [6.0, 'Yes'],
  [4.5, 'Maybe'],
  [0,   'No'],
];
const tier = tierMap.find(([threshold]) => recomputedRounded >= threshold)[1];

return [{
  json: {
    name: candidate.name,
    email: candidate.email,
    location: candidate.location,
    years_experience: candidate.years_experience,
    current_role: candidate.current_role,
    ats_experience: candidate.ats_experience,
    ashby_score: scoring.ashby_score,
    coordination_score: scoring.coordination_score,
    english_score: scoring.english_score,
    startup_score: scoring.startup_score,
    automation_score: scoring.automation_score,
    overall_score: recomputedRounded,
    tier,
    top_strengths: scoring.top_strengths ?? '',
    main_gap: scoring.main_gap ?? '',
    recommendation: scoring.recommendation ?? '',
    scored_at: new Date().toISOString(),
  }
}];

// Rows that were filtered out (missing name or summary)
const candidate = $input.item.json;

return [{
  json: {
    name: candidate.name ?? '(unknown)',
    email: candidate.email ?? '',
    location: candidate.location ?? '',
    years_experience: candidate.years_experience ?? '',
    current_role: candidate.current_role ?? '',
    ats_experience: candidate.ats_experience ?? '',
    ashby_score: 'SKIPPED',
    coordination_score: 'SKIPPED',
    english_score: 'SKIPPED',
    startup_score: 'SKIPPED',
    automation_score: 'SKIPPED',
    overall_score: 'SKIPPED',
    tier: 'SKIPPED',
    top_strengths: '',
    main_gap: 'Row skipped — missing required fields (name or summary)',
    recommendation: 'Row was incomplete and skipped by validation.',
    scored_at: new Date().toISOString(),
  }
}];
